function Get-ParsecIngredientOperations {
    return @{ capture = { param($Arguments, $ExecutionResult, $StateRoot, $RunState, $Definition) $themeState = Invoke-ParsecPersonalizationAdapter -Method 'GetThemeState'; New-ParsecResult -Status 'Succeeded' -Message 'Captured theme state.' -Observed $themeState -Outputs @{ captured_state = $themeState } }; apply = { param($Arguments, $ExecutionResult, $StateRoot, $RunState, $Definition) Invoke-ParsecPersonalizationAdapter -Method 'SetThemeState' -Arguments $Arguments }; verify = { param($Arguments, $ExecutionResult, $StateRoot, $RunState, $Definition) $observed = Invoke-ParsecPersonalizationAdapter -Method 'GetThemeState'; $expected = if ($Arguments.Contains('mode')) { [string] $Arguments.mode } else { $null }; $expectedAppMode = if ($Arguments.Contains('app_mode')) { [string] $Arguments.app_mode } elseif ($expected -and $expected -ne 'Custom') { $expected } else { $null }; $expectedSystemMode = if ($Arguments.Contains('system_mode')) { [string] $Arguments.system_mode } elseif ($expected -and $expected -ne 'Custom') { $expected } else { $null }; if ($expectedAppMode -and $observed.app_mode -ne $expectedAppMode) { return New-ParsecResult -Status 'Failed' -Message 'Application theme mismatch.' -Observed $observed }; if ($expectedSystemMode -and $observed.system_mode -ne $expectedSystemMode) { return New-ParsecResult -Status 'Failed' -Message 'System theme mismatch.' -Observed $observed }; New-ParsecResult -Status 'Succeeded' -Message 'Theme matches.' -Observed $observed }; reset = { param($Arguments, $ExecutionResult, $StateRoot, $RunState, $Definition) if ($Arguments.Contains('captured_state') -and $Arguments.captured_state -is [System.Collections.IDictionary]) { return Invoke-ParsecPersonalizationAdapter -Method 'SetThemeState' -Arguments @{ theme_state = $Arguments.captured_state } }; if ($null -ne $ExecutionResult -and $ExecutionResult.Outputs.captured_state) { return Invoke-ParsecPersonalizationAdapter -Method 'SetThemeState' -Arguments @{ theme_state = $ExecutionResult.Outputs.captured_state } }; Invoke-ParsecPersonalizationAdapter -Method 'SetThemeState' -Arguments $Arguments } }
}
